        WHAT_THE_HELL_ARE_YOU_LOOKING_AT                                      = 10889,  -- What the hell are you looking at?
        I_DON_T_HAVE_TIME_TO_ENTERTAIN_THE                                    = 10890,  -- I don't have time to entertain the likes of you. Get out of my face.
        I_GO_WHERE_I_WANT_WHEN_I_WANT                                         = 10891,  -- I go where I want, when I want. No one can take that from me. Not you, not some president, not anyone.
        HOLD_ON_YOU_HAVEN_T_HAPPENED_TO_HEAR                                  = 10892,  -- Hold on... You haven't happened to hear anything about an Ensetsu, have you? His family's supposed to be living here in Bastok.
        AH_NEVER_MIND_FORGET_YOU_HEARD_ANYTHING_FROM                          = 10893,  -- Ah, never mind. Forget you heard anything from me.
        WHAT_THE_HELL_IS_THIS_DO_I_LOOK                                       = 10894,  -- What the hell is this? Do I look like a goldsmith? Get that thing out of my face!
