        HMPH_I_MIGHT_CONSIDER_HELPING_OUT_BUT_I                               = 10896,  -- Hmph... I might consider helping out [your kingdom/your republic/your federation], but I won't be making you any guarantees.
        HMPH_I_LL_CONSIDER_REMAINING_WITH_BUT_I                               = 10897,  -- Hmph... I'll consider remaining with [your kingdom/your republic/your federation], but I won't make you any guarantees.
        AS_YOU_CAN_SEE_I_STILL_HAVE_MANY                                      = 10898,  -- As you can see, I still have many malms to tread before my training is complete. Perhaps one day our paths will cross again on the fields of battle. Until then, friend.
        THE_BEST_TRAINING_COMES_WHEN_LIVES_ARE_AT                             = 10899,  -- The best training comes when lives are at stake. That is why my journeys often take me to plains of war.
        I_HAVE_RESTED_LONG_ENOUGH_IT_IS_TIME                                  = 10900,  -- I have rested long enough. It is time for me to make my master proud.
