        YOU_DON_T_HAVE_ENOUGH_GIL                                             = 11246,  -- You don't have enough gil.
        YOU_CANNOT_OBTAIN_THE_COME_BACK_AFTER_SORTING_3                       = 11247,  -- You cannot obtain the %. Come back after sorting your inventory.
        WOULD_YOU_BE_SO_KIND_AS_TO_DELIVER                                    = 11248,  -- Would you be so kind as to deliver her to [the entrance to the Gustav Tunnel (B-8)/Bibiki Bay (G-10)/the entrance of Uggalepih Temple (J-11)]?
        ONLY_THOSE_FULFILLING_BOTH_REQUIREMENTS_SET_FORTH_BY                  = 11249,  -- Only those fulfilling both requirements set forth by the alliance may ride a chocobo. First, you must be a soldier of a respectable level in the Allied Forces. Secondly, you must be in possession of %.
        ANY_OF_OUR_FINE_BIRDS_HERE_WILL_BEAR                                  = 11250,  -- Any of our fine birds here will bear you directly to the frontlines of battle. We charge a service fee of # Allied Notes, which goes towards seeing that the chocobos are well taken care of. My records indicate that you currently have # Allied Notes.
        HMMM_IT_LOOKS_LIKE_YOU_DON_T_HAVE                                     = 11251,  -- Hmmm... It looks like you don't have enough Allied Notes. Sorry, but these birds aren't going to feed and groom themselves.
