        THIS_OPERATION_REQUIRES_THAT_YOU_INFILTRATE_THE_ENEMY                 = 11352,  -- This operation requires that you infiltrate the enemy's headquarters and gather intel on both their equipment and reserves.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_INFILTRATE_3                        = 11353,  -- For this operation, you'll have to infiltrate the enemy's northern stronghold, commandeer their prototype weapon, and use it to raze the place to the ground.
        THIS_OPERATION_REQUIRES_THAT_YOU_INFILTRATE_CASTLE_ZVAHL              = 11354,  -- This operation requires that you infiltrate Castle Zvahl and gather intel on the unidentified devices enhancing our enemy's defensive capabilities.
        THIS_OPERATION_REQUIRES_YOU_TO_SEEK_OUT_AND                           = 11355,  -- This operation requires you to seek out and destroy the source of the magical barrier protecting Castle Zvahl's walls.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_HEAD                                = 11356,  -- For this operation, you'll have to head over to the training grounds and teach a nugget what side of the axe to hold.
        THIS_OPERATION_REQUIRES_YOU_TO_ASSIST_IN_THE                          = 11357,  -- This operation requires you to assist in the medical training of some new recruits. See if you can't make some tough-as-nails woundpatchers out of them!
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_SIT                                 = 11358,  -- For this operation, you'll have to sit on your butt and eat Galkan sausage.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_ROUND                               = 11359,  -- For this operation, you'll have to round up supplies for delivery to the frontlines.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_HELP_2                              = 11360,  -- For this operation, you'll have to help resupply our nation's dwindlin' munitions stockpiles.
        THIS_OPERATION_REQUIRES_THAT_YOU_LOCATE_AN_ENEMY                      = 11361,  -- This operation requires that you locate an enemy supply convoy and secure any valuable supplies possible.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_ESCORT                              = 11362,  -- For this operation, you'll have to escort a reinforcement soldier to his destination on the frontlines.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_DELIVER                             = 11363,  -- For this operation, you'll have to deliver supplies to our outposts.
        THIS_OPERATION_REQUIRES_THAT_YOU_SERVE_YOUR_ARMY                      = 11364,  -- This operation requires that you serve your army by offering strategies to best ensure the safe transport of precious cargo.
        FOR_THIS_OPERATION_YOU_LL_HAVE_TO_LOCATE                              = 11365,  -- For this operation, you'll have to locate and remove any suspicious objects lyin' round the capital.
