        GOOD_NOW_GET_BACK_TO_WORK_SOLDIER                                     = 11383,  -- Good. Now get back to work, soldier!
        HUH_I_DON_T_THINK_I_HEARD_YOU                                         = 11384,  -- Huh!? I don't think I heard you right.
        UNBELIEVABLE_THE_PRAEFECTUS_WOULD_BE_CRYING_IN_HIS                    = 11385,  -- Unbelievable! The praefectus would be crying in his grave...if he were a dead sissy like the worthless excuse for a soldier still standing here in front of me! Dismissed!
