        GREETINGS_I_SERVE_AS_SUPPLY_COMMANDER_FOR_THE                         = 11429,  -- Greetings. I serve as supply commander for the Fourth Division's Seventh Cohors.
        ONE_OF_MY_MANY_DUTIES_IS_TO_ENSURE                                    = 11430,  -- One of my many duties is to ensure stability among our ranks by gathering opinions and suggestions and relaying them to the proper authorities.
        PERHAPS_YOU_HAVE_A_COMMENT_I_CAN_PASS                                 = 11431,  -- Perhaps you have a comment I can pass on to the praefectus.
        MY_CONCERNS_EXTEND_TO_PRIVACY_ISSUES_OUR_COMMANDERS                   = 11432,  -- My concerns extend to... Privacy issues. Our commanders. Our battle strategies. Our internal policies. Nothing.
        YOU_NEED_NOT_WORRY_AS_PER_BASTOKAN_LAW                                = 11433,  -- You need not worry, %. As per Bastokan law, I am required to maintain the confidentiality of your identity.
        ONLY_YOUR_OPINION_WILL_BE_REPORTED_TO_THE                             = 11434,  -- Only your opinion will be reported to the praefectus.
        WHILE_ALL_OPINIONS_WILL_BE_CONSIDERED_BY_OUR                          = 11435,  -- While all opinions will be considered by our leaders, this does not necessarily guarantee that your suggestions will be reflected in our nation's strategies.
        THE_BASTOKAN_REPUBLIC_TAKES_PRIDE_IN_THE_DEMOCRACY                    = 11436,  -- The Bastokan Republic takes pride in the democracy established by our forefathers, and any new direction must first be approved by the majority.
        UNDERSTOOD_YOUR_OPINION_HAS_BEEN_NOTED_AND_WILL                       = 11437,  -- Understood. Your opinion has been noted and will be delivered to the praefectus shortly. Thank you, soldier.
        UNDERSTOOD_IF_YOU_EVER_HAVE_A_SUGGESTION_I                            = 11438,  -- Understood. If you ever have a suggestion, I will be here waiting. Good day, soldier.
        ID_600_LOAVES_OF_IRON_BREAD_CHECK_15_000                              = 11439,  -- 600 loaves of iron bread...check. 15,000 copper bullets...check. Ah--
        I_AM_SORRY_SOLDIER_BUT_MY_HANDS_ARE                                   = 11440,  -- I am sorry, soldier, but my hands are tied at the moment. Could you return at a later date?
        AH_SO_YOU_WISH_TO_COMMENT_ON_OUR                                      = 11441,  -- Ah, so you wish to comment on our leaders.
        VERY_WELL_PRAEFECTUS_ZAZARG_IS_EAGER_TO_LEARN                         = 11442,  -- Very well. Praefectus Zazarg is eager to learn how his soldiers view the actions of the Republic's commanders.
        WOULD_YOU_MIND_TELLING_ME_IN_WHO_YOU                                  = 11443,  -- Would you mind telling me in who you place the most trust?
        WHO_DO_YOU_BELIEVE_THE_MOST_COMPETENT_1ST                             = 11444,  -- Who do you believe the most competent? 1st Div. Legatus Berger. 2nd Div. Legatus Eichberg. 3rd Div. Legatus Invincible Shield. Republic Chief of Staff Sturm. Iron Musketeer Commander Krueger. Gold Musketeer Commander Gogol. Quit.
        MAXIMILIAN_BERGER_SINCE_THE_REPUBLIC_S_NUMBING_DEFEAT                 = 11445,  -- Maximilian Berger--since the Republic's numbing defeat at the Battle of Grauberg, the First Division legatus has been vocal in promoting aggressive battlefield tactics.
        LUDWIG_EICHBERG_A_CAUTIOUS_LEADER_WHO_SPECIALIZES_IN                  = 11446,  -- Ludwig Eichberg--a cautious leader who specializes in extended campaigns, the legatus is known for his fervor in the areas of stronghold defense and fortification.
        INVINCIBLE_SHIELD_AN_EXTREMELY_VERSATILE_LEADER_THE_GALKAN            = 11447,  -- Invincible Shield--an extremely versatile leader, the Galkan legatus has become a living legend for his numerous victories on land and sea.
        ADELHEID_STURM_A_SHREWD_STRATEGIST_THE_OPERATIONS_DIVISION            = 11448,  -- Adelheid Sturm--a shrewd strategist, the Operations Division's chief of staff is well versed in the teachings of Schultz martial theory and employs efficient tactics when gathering intelligence on the enemy.
        BARTHOLOMAUS_KRUEGER_NOT_KNOWN_TO_BLINDLY_RUSH_HIS                    = 11449,  -- Bartholomaus Krueger--not known to blindly rush his troops into battle, the legatus believes our nation should first focus on strengthening its forces before engaging the enemy.
        ELIVIRA_GOGOL_A_STRONG_PROPONENT_OF_PREEMPTIVE_BLITZKRIEG             = 11450,  -- Elivira Gogol--a strong proponent of preemptive blitzkrieg tactics, the Gold Musketeer commander is known for her aggressiveness on the battlefield.
        AND_YOU_BELIEVE_THIS_LEADER_S_WISDOM_IS                               = 11453,  -- And you believe this leader's wisdom is what Bastok requires at the moment?
        WELL_ABSOLUTELY_I_NEED_MORE_TIME_TO_THINK                             = 11454,  -- Well...? Absolutely. I need more time to think.
        ALRIGHT                                                               = 11455,  -- Alright.
        WAIT_I_SEEM_TO_RECALL_RECENTLY_RECORDING_YOUR                         = 11456,  -- Wait... I seem to recall recently recording your opinion on our commanders.
        I_BELIEVE_YOU_SAID_OUR_NATION_SHOULD_HEED                             = 11457,  -- I believe you said our nation should heed the strategies of [First Division Legatus Berger/Second Division Legatus Eichberg/Third Division Legatus Invincible Shield/Republic Chief of Staff Sturm/Iron Musketeer Commander Krueger/Gold Musketeer Commander Gogol].
        AH_SO_YOU_WISH_TO_COMMENT_ON_OUR_2                                    = 11458,  -- Ah, so you wish to comment on our current battle strategies.
        WHAT_TACTICS_DO_YOU_BELIEVE_OUR_LEADERS_SHOULD                        = 11459,  -- What tactics do you believe our leaders should employ?
        OUR_CURRENT_SITUATION_REQUIRES_A_PREEMPTIVE_STRIKE_DIVERSIONARY       = 11460,  -- Our current situation requires... A preemptive strike. Diversionary tactics. Battleline preservation. Stronghold defenses. Troop conditioning. Troop training. Reconnaissance. Sabotage. Nothing.
        QUITE_AN_AGGRESSIVE_TACTIC_ON_THE_OTHER_HAND                          = 11461,  -- Quite an aggressive tactic... On the other hand, a preemptive strike can be the quickest way to bring new regions under Bastokan control, even if it results in heavier losses.
        DEPLOYING_A_SMALL_UNIT_OF_ELITE_FORCES_TO                             = 11462,  -- Deploying a small unit of elite forces to distract the enemy while another cuts off vital supply lines... Excellent thinking!
        REINFORCE_DEFENSES_IN_ORDER_TO_MAINTAIN_BATTLELINES_THUS              = 11463,  -- Reinforce defenses in order to maintain battlelines, thus gradually draining the enemy of its influence... A wise decision.
        REINFORCE_STRONGHOLD_DEFENSES_IN_ORDER_TO_PREVENT_ENEMY               = 11464,  -- Reinforce stronghold defenses in order to prevent enemy ambushes and stabilize supply routes. Sound thinking, %.
        BACK_TO_BASICS_SO_SIMPLE_IT_MIGHT_BE                                  = 11465,  -- Back to basics... So simple, it might be just what our forces need.
        THERE_IS_ONLY_SO_MUCH_A_REGULAR_SOLDIER                               = 11466,  -- There is only so much a regular soldier can do. An elite force is necessary for some of our nation's more...delicate operations.
        AH_A_FINE_TACTIC_THE_MORE_INTELLIGENCE_WE                             = 11467,  -- Ah, a fine tactic... The more intelligence we have on the hordes, the more successful we are in our future campaigns.
        A_DANGEROUS_TACTIC_HOWEVER_IF_A_SPECIAL_UNIT                          = 11468,  -- A dangerous tactic... However, if a special unit is able to infiltrate our enemies' strongholds undetected and succeed in sabotaging their lifelines, the tides of battle would most definitely turn in our favor.
        IS_THIS_WHAT_YOU_RECOMMEND_ABSOLUTELY_ON_SECOND                       = 11469,  -- Is this what you recommend? Absolutely! On second thought...
        I_HAVE_ALREADY_DELIVERED_TO_THE_PRAEFECTUS_YOUR                       = 11470,  -- I have already delivered to the praefectus your most recent opinion regarding our battle strategies.
