        SELECT_A_TEMPORARY_ITEM_PRICE_STOCK_NOTHING_AT                        = 11621,  -- Select a temporary item. (Price/Stock) Nothing at this time. Browse another page. %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) %...(#/#) Next page. Previous page.
        BROWSE_WHICH_PAGE_NEVER_MIND_PAGE_1_PAGE                              = 11622,  -- Browse which page? Never mind. Page 1. Page 2. Page 3. Page 4.
        IT_APPEARS_YOU_RE_ALREADY_IN_POSSESSION_OF                            = 11623,  -- It appears you're already in possession of one. I'm sorry, but we can only afford to issue supplies to those who are most in need.
        I_M_SORRY_BUT_WE_RE_FRESH_OUT                                         = 11624,  -- I'm sorry, but we're fresh out of stock for that item.
        YOU_MUST_ATTAIN_A_HIGHER_RANK_IF_YOU                                  = 11625,  -- You must attain a higher rank if you wish to be issued %.
        IS_THERE_ANYTHING_ELSE_YOU_REQUIRE                                    = 11626,  -- Is there anything else you require?
        LET_THE_BLADE_OF_THE_CONQUEROR_ONCE_AGAIN                             = 11627,  -- Let the Blade of the Conqueror once again bring glory to the Kingdom!
        GWAHAHAHA_LET_ME_COOL_YOU_OFF_A_LITTLE                                = 11628,  -- Gwahahaha! Let me cool you off a little before I send you to hell!
        FATHER_LEND_ME_YOUR_STRENGTH                                          = 11629,  -- Father! Lend me your strength!
        FOR_THE_KING                                                          = 11630,  -- For the king!
        MY_SPEAR_IS_LIGHTNING_AND_YOUR_SCREAM_SHALL                           = 11631,  -- My spear is lightning...and your scream shall be the thunder which follows my mighty strike!
        HA_HAH_YOUR_ARROWS_CANNOT_PIERCE_THE_IRON                             = 11632,  -- Ha hah! Your arrows cannot pierce the iron will of a true knight!
        THIS_ARROW_TO_YOUR_HEART_SHALL_BE_ALTANA                              = 11633,  -- This arrow to your heart shall be Altana's final judgment.
        SHOGYO_MUJO_ZESHO_MEPPO_SHOMETSU_METSUI_JAKUMETSU_IRAKU               = 11634,  -- Shogyo Mujo! Zesho Meppo! Shometsu Metsui! Jakumetsu Iraku!
        THERE_IS_NO_ESCAPE_SAVE_DEATH                                         = 11635,  -- There is no escape...save death!
        ALTANA_LET_YOUR_DIVINE_LIGHT_GUIDE_US_TO                              = 11636,  -- Altana! Let your divine light guide us to victory!
        YOU_BARBARIANS_WILL_REGRET_THE_DAY_YOU_SET                            = 11637,  -- You barbarians will regret the day you set foot on Bastokan soil!
        RYAAAAAAAAAH                                                          = 11638,  -- Ryaaaaaaaaah!
        MEN_DO_NOT_FEAR_THE_ENEMY_IT_IS                                       = 11639,  -- Men! Do not fear the enemy! It is our blades they shall fear!
        A_SWIFT_END_IS_THE_ONLY_MERCY_YOU                                     = 11640,  -- A swift end is the only mercy you will receive from me, fiends!
        WATCH_CAREFULLY_BECAUSE_THIS_IS_THE_LAST_THING                        = 11641,  -- Watch carefully, because this is the last thing you'll ever see in this life!
        I_NEVER_LIKED_FIGHTING_ON_LAND_NOW_GIVE                               = 11642,  -- I never liked fighting on land... Now, give me a well armed battleship on the open sea, and I'll have those turtlebacks running for their lives!
        A_SOLDIER_ALWAYS_COMES_PREPARED_HEHEHEHE                              = 11643,  -- A soldier always comes prepared! Hehehehe!
        TO_YOUR_SEATS_BOYS_THE_SHOW_IS_ABOUT                                  = 11644,  -- To your seats, boys! The show is about to begin!
        AHAHAHAHA_MY_HAND_SLIPPED                                             = 11645,  -- Ahahahaha! My hand slipped!
        THIS_IS_YOUR_LAST_CHANCE_THROW_DOWN_YOUR                              = 11646,  -- This is your last chance. Throw down your weapons and your life will be spared. If you refuse...
        THE_GATES_TO_THE_UNDERWORLD_HAVE_OPENED_I                             = 11647,  -- The gates to the underworld have opened! I'll see you on the other side...or not! Wahahahahah!
        THERE_IS_NOTHING_MORE_MAGNIFICENT_THAN_THE_DANCE                      = 11648,  -- There is nothing more magnificent than the dance of flames on the battlefield!
        PHEW_I_THINK_I_VE_HAD_ENOUGH_OF                                       = 11649,  -- <Phew!> I think I've had enough of this volume!
        GUTTLER_GUTTLER_THIRSTY_GUTTLER_WANT_BLOOD_MORE_BLOOD                 = 11650,  -- Guttler: Guttler thirsty! Guttler want blood! More blood!
        TIME_TO_GO_TO_WORK                                                    = 11651,  -- Time to go to work!
        INVINCIBLE_INDESTRUCTIBLE_INDUBITABLE_THE_AGE_OF_THE_CARDIANS         = 11652,  -- Invincible! Indestructible! Indubitable! The age of the Cardians is upon us!
        YOU_OVER_THERE_NO_WAIT_YOU_RE_SUPPOSED                                = 11653,  -- You, over there. No, wait! You're supposed to be on that side! Hold on, which one were you again? Arrrghhh!
        SNORRRE_IS_THAT_THE_BEST_YOU_CAN_DO                                   = 11654,  -- <Snorrre>... Is that the best you can do?
        PETTY_BEASTMAN_HORDES_ARE_NOTHING_COMPARED_TO_GIANT                   = 11655,  -- Petty beastman hordes are nothing compared to giant wildebeests of homeland! I swat you all down like fruit flies!
        YAWN_UM_HOLY_LIGHT_SHOW_THE_WAY                                       = 11656,  -- <Yawn>... Um... Holy light...show the way...?
        THE_PROTECTION_OF_THE_THRONE_COMES_BEFORE_ALL                         = 11657,  -- The protection of the throne comes before all else. Only by direct order of the royaulais will I wield my blade on the battlefield. Such is the duty of the Royal Guards.
        HAH_HAH_HAH_THE_RINGING_OF_STEEL_UPON                                 = 11658,  -- Hah hah hah! The ringing of steel upon steel! The dripping stench of the battlefield! What could be better than war? The nobles can have their balls, I'll do my dance on the front lines!
        HOW_DARE_A_BASEBORN_PEASANT_RAISE_HIS_HER                             = 11659,  -- How dare a baseborn peasant raise his/her] voice to a noble knight!? Begone, before I strike you down myself!
        THE_KINGDOM_S_DEFEAT_AT_JUGNER_STILL_STINGS                           = 11660,  -- The Kingdom's defeat at Jugner still stings. To avenge the souls of those lost on that fateful day, we must join hands and take up arms as one.
        NOT_ONCE_IN_THE_FOUR_HUNDRED_YEARS_SINCE                              = 11661,  -- Not once in the four hundred years since the dawn of the Royal Knights has the Kingdom found itself in such peril. Let us take up our pikes and stand our ground to ensure another four centuries of prosperity!
        IT_IS_OFTEN_IN_TIMES_OF_STRIFE_THAT                                   = 11662,  -- It is often in times of strife that a man's true nature is revealed. Will you stand tall in the face of fear, or run and cower in the wake of your mother's dress?
        WHILE_OUR_HOLY_DOCTRINES_SPECIFICALLY_PROHIBIT_THE_TAKING             = 11663,  -- While our holy doctrines specifically prohibit the taking of another life, you need not hesitate on the battlefield. The Church has branded the beastmen enemies of Altana. The purification must begin! It is the will of the Goddess!!!
        AFTER_YEARS_OF_TRAINING_IN_THE_FAR_EAST                               = 11664,  -- After years of training in the Far East, I return only to find my nation burning at the hands of the infernal beastman hordes. The heathens shall pay dearly... My work has only just begun.
        YOU_HAVE_THE_LOOK_OF_A_FINE_WARRIOR                                   = 11665,  -- You have the look of a fine warrior. It is a pity you are not one of my Crimson Wolves.
        THE_EYES_OF_THE_GODDESS_ARE_EVER_UPON                                 = 11666,  -- The eyes of the Goddess are ever upon us. We must remain steadfast against the evils from without, as well as those from within.
        THE_REPUBLIC_WAS_FORMED_WITH_THE_BLOOD_AND                            = 11667,  -- The Republic was formed with the blood and sweat of the people. The flames of freedom must continue to light our furnaces of strength. The waters of civilization must continue to turn our wheels of ingenuity!
        TURTLE_SLEEPS_IN_A_ROCKY_DENT_CAUSE_HE                                = 11668,  -- Turtle sleeps in a rocky dent 'Cause he's not a citizent Strike him down with sword and stavet Stick a blue flag in his gravet
        WE_MAY_HAVE_THE_UPPER_HAND_IN_TECHNOLOGY                              = 11669,  -- We may have the upper hand in technology and munitions, but the enemy's advantage lies in their sheer numbers. The Allied Campaign will not win in a day, soldier. Make every bullet count.
        THE_METALWORKS_STRATEGIES_ARE_TOO_TIMID_FOR_MY                        = 11670,  -- The Metalworks' strategies are too timid for my taste. The beastmen are nothing but dominoes, waiting to be toppled. A swift, aggressive assault is the only way to victory.
        MOVE_ALONG_SOLDIER_I_HAVE_NOTHING_TO_SAY                              = 11671,  -- Move along, soldier. I have nothing to say to you.
        HALT_IF_YOU_RE_NOT_ONE_OF_THE                                         = 11672,  -- Halt! If you're not one of the Fourth, then get your sorry tail over to the recruitment office on the double! And if you are one of us, then what the hell are you doing here talking to me!? Get back on the battlefield! About...FACE!
        HEAVY_INFANTRY_FIVE_COLUMNS_OF_200_TWO_100                            = 11673,  -- ...Heavy infantry, five columns of 200... Two 100-knight regiments... Enemy force casualties estimated at 5,000... Oh, I apologize, soldier. I've spent the past few nights preparing for a joint operation with San d'Oria's Royal Knights.
        YOU_LOOK_LIKE_YOU_VE_SEEN_BETTER_DAYS                                 = 11674,  -- You look like you've seen better days, soldier. Let me guess, it's the war that's bringing you down. What you need is a little music in your life!
        IF_IT_WEREN_T_FOR_THE_GALKAN_HEAVY                                    = 11675,  -- If it weren't for the Galkan heavy infantry, this nation wouldn't last a month against the turtlebacks. And what thanks do we get? A handful of stale army biscuits!
        HAVE_YOU_EVER_STOPPED_TO_PONDER_WHAT_THAT                             = 11676,  -- Have you ever stopped to ponder what that comet might truly portend? I'd like to believe it is a message of hope--that soon this age of darkness will come to a close...
        OH_WHATEVER_HAS_BECOME_OF_MY_SWEET_WINDURST                           = 11677,  -- Oh, whatever has become of my sweet Windurst? Rabble running through the streets, streets overrun with rabble! Why are you even speaking to me!? Does the title Master Caster no longer garner even an onz of respect!?
        AH_THE_FATES_HAVE_BROUGHT_YOU_TO_GARIRI                               = 11678,  -- Ah, the Fates have brought you to Gariri the Magnificent! Why am I thus called, you ask? Why, because only I was magnificent enough to decryptify those mysteriously marvelous Near Eastern tomes and open a window to...the Other Side!
        WE_ALL_WEAR_MASKS_BECAUSE_DEEP_DOWN_INSIDE                            = 11679,  -- We all wear masks because deep down inside we are nothing but beasts. The question I ask you is, to which do you submit--the mask, or the beast?
        GUTTLER_I_TOLD_YOU_TO_KEEP_QUI_AHAHAHAH                               = 11680,  -- (Guttler! I told you to keep qui--) Ahahahah... Don't mind me, I was just...uh...keeping myself company! (Shhh! If you open your mouth one more ti--) Ahahaha... Uh, were you still there?
        IF_ONLY_THE_PARLIAMENT_OF_PATRIARCHS_WOULD_LOOSEN                     = 11681,  -- If only the Parliament of Patriarchs would loosen the strings on their purses a little more, I would be outside right now roasting up a couple birdmen to snack on!
        HAVE_FUN_WHILE_YOU_CAN_FILTHY_MERCENARY_BECAUSE                       = 11682,  -- Have fun while you can, filthy mercenary, because before long you'll be back on the streets where you belong--replaced by a quiet, obedient army of Cardians!
        NORMALLY_IT_IS_MY_DUTY_TO_PROTECT_THE                                 = 11683,  -- Normally, it is my duty to protect the patriarchs of parliament, but with the fate of Windurst in doubt, I'm forced to lead my loyal pets to the front lines.
        DO_YOU_LIKE_THE_HEADPIECE_I_MADE_IT                                   = 11684,  -- Do you like the headpiece? I made it from my firrrst victim. I wear it to let everrryone know what happens when they cross Mikhe Aryohcha!
        BACK_IN_MY_HOME_ULBUKA_I_HEAR_RUMORS                                  = 11685,  -- Back in my home, Ulbuka, I hear rumors of great riches in eastern lands. But now I am here, and where are riches? I see nothing but Tarus! Ahahahaha!
        YAAAWN_MASTERING_THESE_NEAR_EASTERN_MAGICS_CAN_BE                     = 11686,  -- <Yaaawn>... Mastering these Near Eastern magics can be quite taxing. If I had a choice, I'd rather be back in bed, relaxing...
        I_SAVED_THIS_ONE_ESPECIALLY_FOR_YOU                                   = 11687,  -- I saved this one especially for you!
        HIIIIII_YAH                                                           = 11688,  -- Hiiiiii-yah!
        MY_DEAR_PUPIL_DALZAKK_YOU_STILL_HAVE_MUCH                             = 11689,  -- My dear pupil, Dalzakk. You still have much to learn...
        WITNESS_THE_TRUE_EMBODIMENT_OF_MY_SORROW                              = 11690,  -- Witness the true embodiment of my sorrow.
        HEH_HEH_HEH                                                           = 11691,  -- Heh heh heh!
        GIGGLE                                                                = 11692,  -- <Giggle>...
        WHEHEHEHEH_YOU_THIRSTY_KOPEH                                          = 11693,  -- Wheheheheh! You thirsty, Kopeh?
        COME_KILHWCH_WE_MUST_STRIKE_DOWN_THE_EVIL                             = 11694,  -- Come, Kilhwch! We must strike down the evil which stands before us!
        MY_BROTHERS_AND_SISTERS_RAISE_YOUR_BLADES_FOR                         = 11695,  -- My brothers and sisters! Raise your blades for justice!
        KILHWCH_SILENCE_THOSE_FIENDS                                          = 11696,  -- Kilhwch! Silence those fiends!
        TO_YOUR_FEET_KILHWCH                                                  = 11697,  -- To your feet, Kilhwch!
        LADY_ULLA_WE_MUST_RETREAT                                             = 11698,  -- Lady Ulla. We must retreat.
        HOW_DARE_YOU                                                          = 11699,  -- How dare you!
        THE_RAVEN_SHALT_SPARE_NARY_A_TEAR_FOR                                 = 11700,  -- The raven shalt spare nary a tear for thy demise.
        WATCH_AND_SEE_HOW_A_REAL_MERCENARY_EARRRNS                            = 11701,  -- Watch! And see how a real mercenary earrrns her wage!
        LEAVE_ME_BE_THE_VERGE_OF_BATTLE_IS                                    = 11702,  -- Leave me be. The verge of battle is no time for words.
        FEAR_NOT_MY_FISTS_WILL_GUIDE_US_TO                                    = 11703,  -- Fear not. My fists will guide us to victory.
        MY_DAUGHTER_AWAITS_HER_FATHER_AT_HOME_I                               = 11704,  -- My daughter awaits her father at home. I will permit no Beastman to delay my return.
        BEYOND_THIS_POINT_LIES_THE_SEALED_ROYAL_TOMB                          = 11705,  -- Beyond this point lies the sealed royal tomb of King Ranperre. Tell me, %, do you believe the legends?
        THE_ORC_WAR_MACHINE_DRAWS_NEAR_WE_MUST                                = 11706,  -- The Orc war machine draws near. We must brace ourselves for battle.
        IN_FORMER_TIMES_THIS_ISLAND_WAS_INHABITED_BY                          = 11707,  -- In former times, this island was inhabited by a ferocious tribe of vikings. It is said they braved vast expanses of open sea to arrive here. Romantic, don't you think?
        SURELY_YOU_HAVE_SEEN_THE_TIGERS_THAT_ROAM                             = 11708,  -- Surely you have seen the tigers that roam these downs. They were brought from the northern continent by the Orcs themselves. They are highly prized for their luxurious pelts, though their bloodlust makes them formidable game.
        THE_BROTHERHOOD_OF_THIS_PLACE_ONCE_WELCOMED_ME                        = 11709,  -- The brotherhood of this place once welcomed me long ago. I pray that the years have been kind to them.
        THE_GOLD_MUSKETEERS_OF_THE_REPUBLICAN_ARMY_ARE                        = 11710,  -- The Gold Musketeers of the Republican Army are marshalled by young woman. Such talk is sure to inspire my daughter.
        BASTOK_WAS_FORCED_TO_ABANDON_THE_PALBOROUGH_MINES                     = 11711,  -- Bastok was forced to abandon the Palborough Mines following a Beastman invasion. How an army such as the Republic's could permit such an affront baffles me to no end.
        THE_VILLAGE_ELDER_IN_LA_VAULE_TOLD_ME                                 = 11712,  -- The village elder in La Vaule told me of the so-called wyrm deity of Grauberg. Of course, I am sure it is nothing more than folktales. Still, my curiosity is piqued...
        STRANGE_I_AM_CERTAIN_THE_VEGETATION_OF_THIS                           = 11713,  -- Strange... I am certain the vegetation of this area is different from when I last visited. Surely I would not have allowed myself to forget such beautiful flowers.
        SUCH_DEVASATION_EVEN_THE_RESILIENT_GOOBBUE_WERE_NOT                   = 11714,  -- Such devasation... Even the resilient Goobbue were not able to survive. I wonder if this place shall ever be restored to its former glory...
        HISTORY_TELLS_US_THAT_IT_WAS_IN_THE                                   = 11715,  -- History tells us that it was in the year 381 that San d'Oria's iron-tempered King Lanfeaur R d'Oraguille came these lands to strike a peace with the Quadav. Whatever happened to the bond that was formed...?
        I_HAVE_SEEN_HERE_TWO_TWINS_WHO_BETWEEN                                = 11716,  -- I have seen here two twins who between them share a power for magic the likes of which I have never seen. This is indeed a strange nation.
        UNFORTUNATE_I_HAD_ALWAYS_WISHED_TO_GAZE_UPON                          = 11717,  -- Unfortunate... I had always wished to gaze upon the fabled magic towers of West Sarutabaruta with my own eyes. Yet I fear I may be too late...
        THIS_FORTRESS_IS_LAUDED_AS_THE_IMPREGNABLE_POINT                      = 11718,  -- This fortress is lauded as the impregnable point of Windurst's defenses. Goddess forbid, should it happen to be taken, Windurst is unlikely to last more than a month's time.
        THESE_WINDBLOWN_SANDS_REAK_HAVOC_ON_MY_THROAT                         = 11719,  -- These windblown sands reak havoc on my throat. I look forward to a cup of my daughter's fine Batallia tea.
        TAKE_HEED_I_HAVE_SEEN_BEASTMAN_DUG_BATTLE                             = 11720,  -- Take heed, %. I have seen Beastman-dug battle trenches throughout these plains. Should you be found, your life is forfeit.
        THERE_IS_AN_OMINOUS_FEELING_IN_THE_AIR                                = 11721,  -- There is an ominous feeling in the air... This is no place to linger.
        NEVER_HAVE_I_FELT_A_COLD_AS_PIERCING                                  = 11722,  -- Never have I felt a cold as piercing as this. My teeth chatter and my toes grow numb. We would do well to find a place to warm ourselves.
        I_WONDER_IF_IT_WAS_NOT_SOMEWHERE_NEAR                                 = 11723,  -- I wonder if it was not somewhere near here where minister Francmage was dispatched on the Multinational Expedition some 10 years ago.
        NEVER_DID_I_IMAGINE_THE_DAY_WOULD_COME                                = 11724,  -- Never did I imagine the day would come that I would set foot in this accursed place. Has great is our foe's desperation? Do not lower your guard, %.
        AND_SO_WE_BREACH_THE_ENEMY_S_INNER                                    = 11725,  -- And so we breach the enemy's inner sanctum. Expect anything, %! And don't die on me!
        AS_THE_ALLIED_FORCES_HAVE_LONG_MAINTAINED_THIS                        = 11726,  -- As the Allied Forces have long maintained, this citadel would be ideally suited to the defense of Jeuno.
        A_WELL_CONCEIVED_STRATEGY_A_STRONGHOLD_ESTABLISHED_UNDER              = 11727,  -- A well conceived strategy... A stronghold established under the cover of the nest of these vile crawlers. It is almost surely to be overlooked by the enemy.
        OH_MIGHTY_ALTANA_BE_THE_SWORD_IN_MY                                   = 11728,  -- Oh, mighty Altana, be the sword in my hand. With you, the swift cannot flee, nor the strong escape. Receive mine enemies, for the mercy of the Goddess embraces even the wicked.
        HEH_HEH_HEH_WONDER_WHAT_TECHNIQUE_I_SHOULD                            = 11729,  -- Heh heh heh! Wonder what technique I should try out on these ol' beastmen chumps.
        HAHA_WHO_WILL_BE_THE_NEXT_DARLING_RECIPIENT                           = 11730,  -- Haha... Who will be the next darling recipient of my spells?
        RED_BLOOD_BLUE_BLOOD_ANY_COLORRR_BLOOD_IF                             = 11731,  -- Red blood, blue blood, any colorrr blood. If it bleeds, we can kill it!
        WHAT_S_TAKING_SO_LONG_I_M_GETTING                                     = 11732,  -- What's taking so long? I'm getting all antsy-wantsy! My pets are I are all bad at staying still...
        DO_NOT_FEAR_RIGHTEOUSNESS_WILL_PREVAIL_I_SHALL                        = 11733,  -- Do not fear. Righteousness will prevail. I shall show you victory!
        PROMISE_ME_ONE_THING_SHOULD_ANYTHING_HAPPEN_TO                        = 11734,  -- Promise me one thing. Should anything happen to me... Look after my daughter.
        I_RECKON_I_LL_BE_EARNIN_MY_KEEP                                       = 11735,  -- I reckon I'll be earnin' my keep. Won't be doin' nothin' extra, though. Don't be expectin' me to risk my hide without my due an' proper, mm-hmmm.
        BRAVO_REALLY_IS_A_DEAR_ONCE_YOU_GET                                   = 11736,  -- Bravo really is a dear once you get to know him. It's just that in the heat of battle he... Well, you'll see.
        MY_BLADE_KYOMON_ANTICIPATES_MUCH_BEASTMAN_BLOOD_THIS                  = 11737,  -- My blade, Kyomon, anticipates much beastman blood. This battle may prove interesting, yet.
        LOOK_TO_ME_MORTALS_AND_BE_HAUNTED_FOR                                 = 11738,  -- Look to me, mortals! And be haunted for the rest of your brief time in this world!
        FOR_A_SPLIT_SECOND_YOU_THOUGHT_YOU_SAW                                = 11739,  -- For a split second, you thought you saw Titania turn and shoot you a tiny smile.
        THE_FLOWER_ATOP_BABBAN_NY_MHEILLEA_S_HEAD                             = 11740,  -- The flower atop Babban Ny Mheillea's head appears to be in full bloom!
        RIBBIT_RIBBIT                                                         = 11741,  -- Ribbit! Ribbit!
        YOU_D_BETTER_WATCH_YOUR_BACK                                          = 11742,  -- You'd better watch your back!
        DON_T_TAKE_THIS_PERSONALLY_BUT_I_VE                                   = 11743,  -- Don't take this personally, but I've got children to feed.
        TIME_TO_HAVE_SOME_FUN                                                 = 11744,  -- Time to have some fun!
        RECKON_IT_S_TIME_TUH_EARN_MY_KEEP                                     = 11745,  -- Reckon it's time tuh earn my keep, mm-hmm.
        COME_NOW_BRAVO_IT_S_HIGH_TIME_WE                                      = 11746,  -- Come now, Bravo! It's high time we taught these beasts what a wyvern is truly capable of!
        HEHE_SO_MANY_WILLING_TO_BE_SACRIFICED                                 = 11747,  -- Hehe, so many willing to be sacrificed!
        HMPH_PERHAPS_I_SHOULD_JUST_BURN_THE_EYES                              = 11748,  -- Hmph. Perhaps I should just burn the eyes of these infidels with my true form.
        I_FEAR_NOT_DEATH_FOR_THE_GODDESS_AWAITS                               = 11749,  -- I fear not death, for the Goddess awaits us with open arms.
        IT_IS_NOT_YET_YOUR_TIME                                               = 11750,  -- It is not yet your time.
        BE_STRONG_FOR_THE_GODDESS_IS_WITH_YOU                                 = 11751,  -- Be strong, for the Goddess is with you, always.
        RETURN_TO_THE_DUST_WHENCE_YOU_CAME_RANDGRITH                          = 11752,  -- Return to the dust whence you came! Randgrith!!!
        SAINTS_AND_HEROES_GLORY_AND_DESPAIR_OF_THESE                          = 11753,  -- Saints and heroes...glory and despair... Of these I shall sing unto my dying breath.
        TWHEN_WORK_HAS_ENDED_STAY_NOT_LATE_RETURN                             = 11754,  -- tWhen work has ended stay not late. @Return to where thy dearest awaits.
        TO_GENTLE_GODDESS_OF_THE_DAWN_THOU_BRIGHTEN                           = 11755,  -- tO gentle Goddess of the Dawn, thou brighten the black of night. @Hear our song and heed our call, and bathe us in your delight.
        TPRESS_FORWARD_VALIANT_SOLDIERS_GLORY_DRAWS_NEARER_STILL              = 11756,  -- tPress forward valiant soldiers, glory draws nearer still. @Thy deeds shall resound forever, by my stirring song fulfilled.
        TLOYAL_CHILDREN_OF_ALTANA_ARISE_AND_BE_SUSTAINED                      = 11757,  -- tLoyal children of Altana, arise and be sustained. @Be nourished in thine undying faith, and bask in victory's refrain.
        TSING_DANCE_LAUGH_AND_CRY_LET_SWEAT_RAIN                              = 11758,  -- tSing! Dance! Laugh, and cry! Let sweat rain down in floods! @Ride upon this rhythmic beat, make seethe thy red life blood!
        TDANCE_THINE_ELEGANT_AIRY_STEPS_THAT_HAS_WON                          = 11759,  -- tDance thine elegant, airy steps that has won a thousand hearts. @Enchant, enthrall, and captivate, treat none with disregard.
