        THE_ALLIED_SIGIL_IS_A_TYPE_OF_BENEFICIAL                              = 12395,  -- The Allied Sigil is a type of beneficial magic spell offered to all those participating in the Allied Campaign as a bonus for their services.
        HOWEVER_THE_EFFECTS_OF_THIS_SPELL_VARY_DEPENDING                      = 12396,  -- However, the effects of this spell vary depending on the performance of your nation's army.
        ARMIES_WHICH_EMPLOY_POWERFUL_FREELANCES_ALSO_RECEIVE_VARIOUS          = 12397,  -- Armies which employ powerful freelances also receive various benefits to their Sigil.
