        HEAR_YE_HEAR_YE_FOR_ALL_THE_LATEST                                    = 12409,  -- Hear ye! Hear ye! For all the latest news on the Allied Campaign, you need look no further than [/Voucheramme of the Knights of the Scarlet Boar/Hinrich of the Republican Intelligence Agency/Dallus-Mallus of the Aurastery]!
        WHAT_KNOWLEDGE_DO_YOU_SEEK_LATEST_CAMPAIGN_INTEL                      = 12410,  -- What knowledge do you seek? Latest Campaign intel. Details on current war climate. Details on unit movements. More specific information. Nothing in particular.
        VIEW_WHICH_INFORMATION_OUR_NATION_S_STRATEGY_ROYAL                    = 12411,  -- View which information? Our nation's strategy. Royal Army conditions. Republican Army conditions. Federation Army conditions. Orcish Host conditions. Shieldwarriors conditions. Theomilitary conditions. Dark Kindred conditions. Return.
