        SO_I_TRUST_THERE_WILL_BE_NO_OBJECTIONS                                = 13115,  -- So I trust there will be no objections if I were to ask you to leave him in my care until the commencement of court-martial?
        ID_13116                                                              = 13116,  -- ...
        AS_YOU_WISH_MISTER_PRESIDENT_IF_YOUR_EXCELLENCY                       = 13117,  -- As you wish, Mister President. If Your Excellency will act as guarantor and provide the pertinent documentation, I will agree to this proposal.
        BUT_IF_I_MAY_BE_SO_BOLD_THE                                           = 13118,  -- But if I may be so bold, the Senate may not be so lenient regarding this unorthodox solution.
        YOUR_CONCERN_IS_APPRECIATED_DIETER_BUT_QUITE_UNNECESSARY              = 13119,  -- Your concern is appreciated, Dieter, but quite unnecessary.
        NOW_FIVE_MOONS_OR_SHOULD_I_SAY_GALAGG                                 = 13120,  -- Now, Five Moons...or should I say, Galagg. You are to resume Mythril Musketeer duty as before. Understood?
        IF_THE_CAPTAIN_WILL_STILL_HAVE_ME                                     = 13121,  -- If the captain will still have me....
        THE_ANSWER_TO_THAT_QUESTION_IS_OBVIOUS_SOLDIER                        = 13122,  -- The answer to that question is obvious, soldier.
        HAHAHA_THEN_IT_S_SETTLED                                              = 13123,  -- Hahaha... Then it's settled.
        OUR_NATION_MUST_NEVER_AGAIN_BE_DIVIDED                                = 13124,  -- Our nation must never again be divided.
        GALAGG_YOUR_ROLE_IN_ENSURING_A_UNIFIED_BASTOK                         = 13125,  -- Galagg. Your role in ensuring a unified Bastok will be instrumental--of this I am certain. Much rests upon your able shoulders.
        YES_YOUR_EXCELLENCY                                                   = 13126,  -- Yes, Your Excellency.
        AND                                                                   = 13127,  -- And %.
        CAPTAIN_KLARA_HAS_TOLD_ME_OF_YOUR_PART                                = 13128,  -- Captain Klara has told me of your part in destroying the enemy warmachines in the Ruhotz Silvermines. You have done our nation a great service.
        I_THANK_YOU_ON_BEHALF_OF_ALL_THE                                      = 13129,  -- I thank you on behalf of all the citizens of Bastok.
        PLEASE_ACCEPT_THIS_AS_A_SYMBOL_OF_MY                                  = 13130,  -- Please accept this as a symbol of my heartfelt gratitude.
        WE_LOOK_FORWARD_TO_YOUR_CONTINUED_SUPPORT_IN                          = 13131,  -- We look forward to your continued support in the future endeavors of our nation.
        SIGH_ALL_S_WELL_THAT_ENDS_WELL                                        = 13132,  -- <Sigh> All's well that ends well!
        FIVE_MOONS_DON_T_YOU_EVEN_DARE_THINK                                  = 13133,  -- Five Moons, don't you even dare think about putting us through such a mess again!
        C_CAPTAIN_I                                                           = 13134,  -- C-Captain, I...
