        ENRICH_YES_NO                                                         = 13713,  -- Enrich %? Yes. No.
        YOUR_HAS_BEEN_ENRICHED_TO_LEVEL_CRUOR_EXPENDED                        = 13714,  -- Your % has been enriched to level #! (Cruor expended: #)
        THE_HAS_BEEN_ENRICHED_TO_ITS_MAXIMUM_LEVEL                            = 13715,  -- The % has been enriched to its maximum level!
