        IT_SEEMS_YOU_RE_SHORT_ON_SOLDIER_COME                                 = 14693,  -- It seems you're short on [Conquest Points/Imperial Standing credits/Allied Notes], soldier. Come back when you've got a bit more seasoning under your belt.
        PROCEED_REQUIRED_YES_NO                                               = 14694,  -- Proceed? (Required [Points/Standing/Notes]: #) Yes. No.
        OBTAINS_IN_EXCHANGE_FOR                                               = 14695,  -- % obtains % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        OBTAINS_IN_EXCHANGE_FOR_2                                             = 14696,  -- % obtains # % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        OBTAINS_IN_EXCHANGE_FOR_3                                             = 14697,  -- % obtains % in exchange for # [Conquest Points/credits of Imperial Standing/Allied Notes].
        THIS_WILL_COST_YOU_2                                                  = 14698,  -- This % will cost you # [Conquest Points/credits of Imperial Standing/Allied Notes].
        YOU_ALREADY_HAVE_AND_I_M_NOT_AUTHORIZED                               = 14699,  -- You already have %, and I'm not authorized to furnish you with another. Resources are in short supply. You'll have to make do with what you've already got.
        HOW_MANY                                                              = 14708,  -- How many? ( [Conquest Points/Imperial Standing/Allied Notes]: #)
        YOU_MAY_PURCHASE_UP_TO_AT_A_TIME_2                                    = 14709,  -- You may purchase up to # at a time.
        WELCOME_TO_THE_MHMU_S_PORTER_SERVICE_KUPO                             = 14710,  -- Welcome to the MHMU's porter service, kupo! Which of your burdensome belongings shall I take off your hands today?
        DO_SOMETHING_KUPO_PORTER_SERVICE_BUY_A_STORAGE                        = 14711,  -- Do something, kupo? Porter service? Buy a storage slip. No, thank you.
        IS_YOUR_GOBBIEBAG_SPLITTING_AT_THE_SEAMS_MOG                          = 14712,  -- Is your gobbiebag splitting at the seams? Mog Safe spilling over? Why, an accomplished adventurer like yourself surely has more stuff than you know what to do with.
        THAT_S_WHERE_I_COME_IN_KUPO_I                                         = 14713,  -- That's where I come in, kupo. I'll gladly hold onto your prized possessions, freeing you space to gather up even grander goodies.
        TO_MAKE_USE_OF_MY_SERVICES_FIRST_YOU                                  = 14714,  -- To make use of my services, first you'll need to buy one of these storage slips for the low, low fee of # gil.
        STORAGE_SLIPS_COME_IN_NUMEROUS_VARIETIES_KUPO_EACH                    = 14715,  -- Storage slips come in numerous varieties, kupo, each corresponding to a different type of item.
        YOU_LL_WANT_TO_PERUSE_THE_FINE_PRINT                                  = 14716,  -- You'll want to peruse the fine print closely, so you don't end up paying good gil for a scrap of parchment useless for the particular item you wish to store.
        NOT_THAT_WE_MOOGLES_WOULD_OBJECT_TO_THAT                              = 14717,  -- Not that we moogles would object to that sort of donation, kupo.
